/**
 * Options for the slugify function.
 */
export interface SlugifyOptions {
  /** Character used to replace spaces and separators. Defaults to '-'. */
  separator?: string;
  /** Whether to convert to lowercase. Defaults to true. */
  lowercase?: boolean;
}

/**
 * Converts a string into a URL-friendly slug.
 *
 * Strips diacritics, replaces non-alphanumeric characters with the separator,
 * collapses consecutive separators, and trims separators from both ends.
 *
 * @param input - The string to slugify.
 * @param options - Optional configuration.
 * @returns The slugified string.
 *
 * @example
 * ```ts
 * slugify('Hello World!')        // 'hello-world'
 * slugify('Café au lait')        // 'cafe-au-lait'
 * slugify('foo  --  bar')         // 'foo-bar'
 * slugify('Hello World', { separator: '_' }) // 'hello_world'
 * ```
 */
export function slugify(input: string, options: SlugifyOptions = {}): string {
  const { separator = '-', lowercase = true } = options;

  let result = input
    // Decompose unicode characters and strip diacritical marks
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    // Replace non-alphanumeric characters with separator
    .replace(/[^a-zA-Z0-9]+/g, separator)
    // Collapse consecutive separators
    .replace(new RegExp(`\\${separator}{2,}`, 'g'), separator)
    // Trim separator from start and end
    .replace(new RegExp(`^\\${separator}|\\${separator}$`, 'g'), '');

  if (lowercase) {
    result = result.toLowerCase();
  }

  return result;
}

/**
 * Options for the truncate function.
 */
export interface TruncateOptions {
  /** The maximum length of the returned string (including suffix). Defaults to 30. */
  length?: number;
  /** The string to append when truncation occurs. Defaults to '...'. */
  suffix?: string;
}

/**
 * Truncates a string to a specified maximum length, appending a suffix if truncated.
 *
 * If the input string is shorter than or equal to the maximum length, it is returned as-is.
 * Otherwise, it is trimmed so that the result (including the suffix) fits within the length.
 *
 * @param input - The string to truncate.
 * @param options - Optional configuration.
 * @returns The truncated string.
 *
 * @example
 * ```ts
 * truncate('Hello, World!', { length: 10 }) // 'Hello, ...',
 * truncate('Short')                         // 'Short'
 * truncate('Hello, World!', { length: 10, suffix: '…' }) // 'Hello, Wo…'
 * ```
 */
export function truncate(input: string, options: TruncateOptions = {}): string {
  const { length = 30, suffix = '...' } = options;

  if (input.length <= length) {
    return input;
  }

  const trimLength = length - suffix.length;

  if (trimLength <= 0) {
    return suffix.slice(0, length);
  }

  return input.slice(0, trimLength) + suffix;
}

/**
 * Splits a string into words by detecting boundaries:
 * - Non-alphanumeric characters (spaces, hyphens, underscores, etc.)
 * - Transitions from lowercase to uppercase (camelCase boundaries)
 * - Transitions from multiple uppercase to lowercase (e.g., 'HTMLParser' -> ['HTML', 'Parser'])
 *
 * @param input - The string to split.
 * @returns An array of words.
 */
function splitWords(input: string): string[] {
  // Replace camelCase boundaries with a separator
  const expanded = input
    // Insert separator before uppercase letters that follow lowercase letters
    .replace(/([a-z])([A-Z])/g, '$1\0$2')
    // Insert separator before uppercase letter followed by lowercase, when preceded by uppercase
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1\0$2');

  // Split on non-alphanumeric characters or the null separator
  return expanded
    .split(/[^a-zA-Z0-9]+|\0/)
    .filter((word) => word.length > 0);
}

/**
 * Capitalizes the first character of a string.
 *
 * @param input - The string to capitalize.
 * @returns The string with its first character uppercased.
 *
 * @example
 * ```ts
 * capitalize('hello')   // 'Hello'
 * capitalize('HELLO')   // 'HELLO'
 * capitalize('')        // ''
 * ```
 */
export function capitalize(input: string): string {
  if (input.length === 0) return '';
  return input.charAt(0).toUpperCase() + input.slice(1);
}

/**
 * Converts a string to camelCase.
 *
 * Splits on word boundaries, lowercases the first word, and capitalizes
 * subsequent words.
 *
 * @param input - The string to convert.
 * @returns The camelCase string.
 *
 * @example
 * ```ts
 * camelCase('hello world')     // 'helloWorld'
 * camelCase('foo-bar-baz')     // 'fooBarBaz'
 * camelCase('FooBar')          // 'fooBar'
 * camelCase('__FOO_BAR__')     // 'fooBar'
 * ```
 */
export function camelCase(input: string): string {
  const words = splitWords(input);
  if (words.length === 0) return '';

  return words
    .map((word, index) => {
      const lower = word.toLowerCase();
      if (index === 0) return lower;
      return lower.charAt(0).toUpperCase() + lower.slice(1);
    })
    .join('');
}

/**
 * Converts a string to kebab-case.
 *
 * Splits on word boundaries and joins with hyphens, all lowercase.
 *
 * @param input - The string to convert.
 * @returns The kebab-case string.
 *
 * @example
 * ```ts
 * kebabCase('Hello World')     // 'hello-world'
 * kebabCase('fooBarBaz')       // 'foo-bar-baz'
 * kebabCase('__FOO_BAR__')     // 'foo-bar'
 * ```
 */
export function kebabCase(input: string): string {
  return splitWords(input)
    .map((word) => word.toLowerCase())
    .join('-');
}

/**
 * string-utils — A TypeScript string utility library.
 *
 * @module
 */

export { slugify } from './slugify';
export type { SlugifyOptions } from './slugify';

export { truncate } from './truncate';
export type { TruncateOptions } from './truncate';

export { capitalize, camelCase, kebabCase } from './case';

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['tests/**/*.test.ts'],
  },
});

import { describe, it, expect } from 'vitest';
import { slugify } from '../src/slugify';

describe('slugify', () => {
  it('should convert a simple string to a slug', () => {
    expect(slugify('Hello World')).toBe('hello-world');
  });

  it('should handle multiple spaces', () => {
    expect(slugify('hello   world')).toBe('hello-world');
  });

  it('should strip diacritical marks', () => {
    expect(slugify('Café au lait')).toBe('cafe-au-lait');
  });

  it('should handle special characters', () => {
    expect(slugify('Hello, World! How are you?')).toBe('hello-world-how-are-you');
  });

  it('should collapse multiple hyphens', () => {
    expect(slugify('foo  --  bar')).toBe('foo-bar');
  });

  it('should trim hyphens from edges', () => {
    expect(slugify('  hello world  ')).toBe('hello-world');
  });

  it('should handle empty string', () => {
    expect(slugify('')).toBe('');
  });

  it('should handle numbers', () => {
    expect(slugify('Section 3.2: Overview')).toBe('section-3-2-overview');
  });

  it('should support custom separator', () => {
    expect(slugify('Hello World', { separator: '_' })).toBe('hello_world');
  });

  it('should support preserving case', () => {
    expect(slugify('Hello World', { lowercase: false })).toBe('Hello-World');
  });

  it('should handle mixed unicode characters', () => {
    expect(slugify('üöä straße')).toBe('uoa-strasse');
  });

  it('should handle consecutive special characters', () => {
    expect(slugify('a!!!b???c')).toBe('a-b-c');
  });
});

import { describe, it, expect } from 'vitest';
import { truncate } from '../src/truncate';

describe('truncate', () => {
  it('should return the string unchanged if within length', () => {
    expect(truncate('Hello', { length: 10 })).toBe('Hello');
  });

  it('should truncate and add default suffix', () => {
    expect(truncate('Hello, World!', { length: 10 })).toBe('Hello, ...');
  });

  it('should use default length of 30', () => {
    const long = 'a'.repeat(50);
    const result = truncate(long);
    expect(result).toHaveLength(30);
    expect(result.endsWith('...')).toBe(true);
  });

  it('should use custom suffix', () => {
    expect(truncate('Hello, World!', { length: 10, suffix: '…' })).toBe('Hello, Wo…');
  });

  it('should handle empty string', () => {
    expect(truncate('')).toBe('');
  });

  it('should handle string exactly at length limit', () => {
    expect(truncate('Hello', { length: 5 })).toBe('Hello');
  });

  it('should handle very short length with long suffix', () => {
    expect(truncate('Hello, World!', { length: 2, suffix: '...' })).toBe('..');
  });

  it('should handle length of zero', () => {
    expect(truncate('Hello', { length: 0 })).toBe('');
  });

  it('should preserve spaces in truncated output', () => {
    expect(truncate('The quick brown fox', { length: 12 })).toBe('The quick...');
  });
});

import { describe, it, expect } from 'vitest';
import { capitalize, camelCase, kebabCase } from '../src/case';

describe('capitalize', () => {
  it('should capitalize the first character', () => {
    expect(capitalize('hello')).toBe('Hello');
  });

  it('should leave already-capitalized strings unchanged', () => {
    expect(capitalize('Hello')).toBe('Hello');
  });

  it('should handle all-uppercase input', () => {
    expect(capitalize('HELLO')).toBe('HELLO');
  });

  it('should handle empty string', () => {
    expect(capitalize('')).toBe('');
  });

  it('should handle single character', () => {
    expect(capitalize('a')).toBe('A');
  });
});

describe('camelCase', () => {
  it('should convert space-separated words', () => {
    expect(camelCase('hello world')).toBe('helloWorld');
  });

  it('should convert hyphen-separated words', () => {
    expect(camelCase('foo-bar-baz')).toBe('fooBarBaz');
  });

  it('should convert PascalCase to camelCase', () => {
    expect(camelCase('FooBar')).toBe('fooBar');
  });

  it('should handle underscores and leading/trailing separators', () => {
    expect(camelCase('__FOO_BAR__')).toBe('fooBar');
  });

  it('should handle empty string', () => {
    expect(camelCase('')).toBe('');
  });

  it('should handle single word', () => {
    expect(camelCase('hello')).toBe('hello');
  });

  it('should handle acronyms', () => {
    expect(camelCase('HTMLParser')).toBe('htmlParser');
  });

  it('should handle mixed separators', () => {
    expect(camelCase('foo_bar-baz qux')).toBe('fooBarBazQux');
  });
});

describe('kebabCase', () => {
  it('should convert space-separated words', () => {
    expect(kebabCase('Hello World')).toBe('hello-world');
  });

  it('should convert camelCase', () => {
    expect(kebabCase('fooBarBaz')).toBe('foo-bar-baz');
  });

  it('should handle underscores', () => {
    expect(kebabCase('__FOO_BAR__')).toBe('foo-bar');
  });

  it('should handle empty string', () => {
    expect(kebabCase('')).toBe('');
  });

  it('should handle single word', () => {
    expect(kebabCase('hello')).toBe('hello');
  });

  it('should handle PascalCase', () => {
    expect(kebabCase('FooBarBaz')).toBe('foo-bar-baz');
  });

  it('should handle acronyms', () => {
    expect(kebabCase('HTMLParser')).toBe('html-parser');
  });
});

export function slugify(input: string, options: SlugifyOptions = {}): string {
  const { separator = '-', lowercase = true } = options;

  let result = input
    // Replace common ligatures and special characters that NFD won't decompose
    .replace(/ß/g, 'ss')
    .replace(/æ/g, 'ae')
    .replace(/œ/g, 'oe')
    // Decompose unicode characters and strip diacritical marks
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    // Replace non-alphanumeric characters with separator
    .replace(/[^a-zA-Z0-9]+/g, separator)
    // Collapse consecutive separators
    .replace(new RegExp(`\\${separator}{2,}`, 'g'), separator)
    // Trim separator from start and end
    .replace(new RegExp(`^\\${separator}|\\${separator}$`, 'g'), '');

  if (lowercase) {
    result = result.toLowerCase();
  }

  return result;
}

